insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, увидев <а>толпы, Он <1>поднялся на <б>гору. И когда Он сел, подошли к Нему Его <2>ученики. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, <а>открыв уста, Он учил их и говорил:',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Блаженны <2а>нищие <3>духом, ибо их есть <4б>царство небес.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>скорбящие, ибо они будут <2б>утешены. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>кроткие, ибо они <2б>унаследуют землю.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны алчущие и <а>жаждущие <1б>праведности, ибо они <2в>насытятся',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>милостивые, ибо им будет <2>явлена милость. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>чистые сердцем, ибо они <2б>увидят Бога.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>миротворцы, ибо они будут названы <2б>сыновьями Божьими.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны <1а>гонимые за <б>праведность, ибо <2>их есть <в>царство небес.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Блаженны вы, когда будут <1а>поносить вас, и <б>гнать, и лживо говорить против вас всякое <в>зло <2>из-за Меня.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<а>Радуйтесь и ликуйте, ибо велика ваша <1>бнаграда на небесах; ибо так <в>гнали <2>пророков, которые были до вас.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Вы <2а>соль земли. Но если соль станет <3б>пресной, чем сделать её солёной? Она уже <в>ни на что не годна, разве только <4г>выбросить её, чтобы её <5>топтали люди.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы <1а>свет мира. Невозможно, чтобы <2б>город, расположенный на горе, был скрыт.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И, зажигая <а>светильник, не ставят его под <1>сосуд, а ставят на <2б>подставку, и он сияет всем, кто в доме.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Пусть так же <а>сияет ваш свет перед людьми, чтобы они видели ваши <1б>добрые дела и <2в>прославляли вашего <3>Отца, который на небесах.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Не думайте, что Я пришёл упразднить <а>закон или пророков; Я пришёл не упразднить, а <2б>исполнить. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо истинно говорю вам: пока не уйдёт <1а>небо и земля, ни одна <2>йота и ни одна <3>чёрточка ни в коем случае не уйдёт из закона, пока всё не произойдёт.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Итак, кто отменит одну из <а>малейших из этих <1>заповедей и так научит людей, будет назван <б>малейшим в <в>царстве небес; а кто выполнит их и научит им, тот будет назван <г>великим в царстве небес.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ибо говорю вам, что если ваша <1а>праведность не превзойдёт праведности <2>книжников и фарисеев, то вы ни в коем случае не <3б>войдёте в царство небес.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что древним было сказано: «<а>Не убивай; а кто убьёт, будет подлежать <б>суду».',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А <1>Я говорю вам, что всякий, кто <2а>гневается на своего <3>брата, будет подлежать <4б>суду. А кто скажет своему брату: «<5>Раќа», — будет подлежать суду <6в>синедриона; а кто скажет: «<7>Мор́э», — будет подлежать <8г>Геенне огненной. ',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Итак, если ты будешь приносить свой <1а>дар на <2б>жертвеннике и там вспомнишь, что твой <в>брат имеет <3>что-то против тебя,',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('То оставь там свой дар перед жертвенником и <1>прежде иди и <2а>помирись со своим братом, и тогда приходи и приноси свой дар.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('<1>Скорее благоволи к своему <2а>противнику в суде, пока ты с ним <3>в пути, чтобы не <4>отдал тебя противник судье, а судья служителю, и ты не был брошен в тюрьму.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Истинно говорю тебе: ни в коем случае не <1>выйдешь оттуда, пока не <а>выплатишь последнего <2>кодранта.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Вы слышали, что было сказано: «<а>Не прелюбодействуй».',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, что всякий, кто <а>смотрит на женщину с тем, чтобы вожделеть её, уже <б>прелюбодействовал с ней в своём <1в>сердце.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Если же твой правый <а>глаз служит для тебя преткновением, <1>вырви его и брось от себя, ибо лучше для тебя, чтобы погиб один из твоих членов, чем чтобы всё твоё тело было брошено в <2б>Геенну.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И если твоя правая <а>рука служит для тебя преткновением, <1>отруби её и брось от себя, ибо лучше для тебя, чтобы погиб один из твоих членов, чем чтобы всё твоё тело пошло в <б>Геенну.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('И было сказано: «<а>Кто <1>разведётся со своей женой, пусть даст ей разводное свидетельство».',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, что <1>всякий, кто <а>разводится со своей женой, кроме как по причине <2>блуда, побуждает её прелюбодействовать, и кто женится на разведённой, прелюбодействует.',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('Ещё вы слышали, что древним было сказано: «<1а>Не нарушай клятву, а <2б>исполняй перед Господом свои клятвы».',2,1,5,1);
insert into bible_verse (text, testament_id, book_id, chapter, verse) values ('А Я говорю вам, чтобы вы <а>не клялись совсем: ни <1б>небом, потому что это престол Божий;',2,1,5,1);
